class Node{
    Node prev;
    List<Node>next;
    int id;
    String name;
    Node(int id){
        this.id = id;
    }
}
class Folder {
    int id;
    List<Integer> subFolders;
    String name;
    Folder(int id, String name){
        this.id = id;
        this.name = name;
    }
}
class FindPathFolder {

    public static void printPath(List<Folder>list, int printId){

        int len = list.size();
        Map<Integer, Node>folderMap = new HashMap<>();
        Node rootNode = new Node(-1);

        for(int i=0; i<len; i++){
            Folder currFolder = list.get(i);
            int currId = currFolder.id;
            Node currNode;

            if(folderMap.containsKey(currId)){
                currNode = folderMap.get(currId);
                currNode.name = currFolder.name;
            }
            else{
                currNode = new Node(currId);
                currNode.name = currFolder.name;
                if(currId != 0)
                    folderMap.put(currId, currNode);
            }
            List<Integer>subFolders = currFolder.subFolders;
            List<Node>subNodes = new ArrayList<>();
            if(subFolders != null){
                for(int j=0; j<subFolders.size(); j++){
                    int subId = subFolders.get(j);
                    Node subNode;
                    if(folderMap.containsKey(subId)){
                        subNode = folderMap.get(subId);
                    }
                    else{
                        subNode = new Node(subId);
                        folderMap.put(subId, subNode);
                    }
                    subNode.prev = currNode;
                    subNodes.add(subNode);
                    currNode.next = subNodes;
                }
            }
            if(currId == 0){
                currNode.prev = rootNode;
            }
        }

        if(!folderMap.containsKey(printId)){
            System.out.println("invalid Id");
            return;
        }
        Node node = folderMap.get(printId);

        List<String>path = new ArrayList<>();

        while(node.id != -1){
            path.add(node.name);
            node = node.prev;
        }
        for(int i=path.size()-1; i>=0; i--){
            System.out.println(path.get(i));
        }
    }


    public static void main(String[] args) {
        // String list = [Folder(0, [7, 3], “abc”), Folder(0, [], “xyz”), Folder(3, [], “pqr”), Folder(8, [], “def”), Folder(7, [9], “ijk”), Folder(9, [], “lmn”)];

